fun tickerFlow(intervalMs: Long): Flow<Long> = callbackFlow {
    var count = 0L
    val handler = Handler(Looper.getMainLooper())
    val runnable = object : Runnable {
        override fun run() {
            trySend(count++)
            handler.postDelayed(this, intervalMs)
        }
    }
    handler.post(runnable)
    awaitClose { handler.removeCallbacksAndMessages(null) }
}

suspend fun <T> retryBuggy(
    maxRetries: Int = 3,
    block: suspend () -> T
): T {
    var lastException: Exception? = null
    repeat(maxRetries) {
        try {
            return block()
        } catch (e: Exception) {
            lastException = e
        }
    }
    throw lastException!!
}

